            sample: sy,
            samplesPerAxis: sampleGrid.samplesPerAxis,
          );
          final coordinate = viewport.coordinate(nx: nx, ny: ny);

          final color = formula(
            coordinate.$1,
            coordinate.$2,
            iterations,
            bailout,
            juliaC,
          );
          rAcc += color.$1;
          gAcc += color.$2;
          bAcc += color.$3;
